-    top: number;
-    left: number;
-  } | null>(null);
+  const [overlayPos, setOverlayPos] = useState<{
+    top: number;
+    right: number;
+  } | null>(null);

   // inside compute():
-      setOverlayPos({
-        top: r.top + r.height / 2,
-        left: r.left,
-      });
+      const GAP = 8; // --portfolio-spacer-1x
+      setOverlayPos({
+        top:   r.top + r.height / 2,
+        right: window.innerWidth - r.left + GAP,
+      });

   // portaled div inline style:
-      style={
-        overlayPos
-          ? { top: `${overlayPos.top}px`, left: `${overlayPos.left}px` }
-          : { top: 0, left: 0, visibility: "hidden" }
-      }
+      style={
+        overlayPos
+          ? { top: `${overlayPos.top}px`, right: `${overlayPos.right}px` }
+          : { top: 0, right: 0, visibility: "hidden" }
+      }
```

### `src/components/ui/ScrollSpy/ScrollSpy.module.scss` — diff summary

```diff
 .highlightLabelAnchor {
   position: fixed;
-  transform: translate(
-    calc(-100% - var(--portfolio-spacer-1x)),
-    -50%
-  );
+  transform: translateY(-50%);
   color: #fff;
   mix-blend-mode: difference;
   z-index: var(--portfolio-z-scrollspy);
   pointer-events: none;
-  will-change: top, left;
+  will-change: top, right;
 }
```

---

## Why the user's attempted fix (re-anchoring to the notch container) had no visible effect

The comment in the current code says "I already tried fixing the anchor from inner tick to notch container." That changes **which** `getBoundingClientRect()` is measured — but since both the tick and the notch container are at almost the same `left` position (the notch is 28px wide, the tick sits inside it right-aligned), `r.left` barely changes (by a few pixels). The root cause — `translate(-100%)` computing against a not-yet-painted self-width — was unaffected by re-targeting the measurement source.

---

## Principle

**AP-070** — Never rely on `translate(-100%)` (self-width relative) for placement of an element whose width is unknown at the time the transform is first applied. The browser resolves `translate(-100%)` against the element's own computed width; if that width is 0 on first paint (as with a freshly-portaled `position: fixed` element before layout), the shift is 0 and the element sits at the raw coordinate. Use `right: <distance-from-viewport-right>` instead — the browser resolves `right` during layout, after the element's width is known, without any self-reference circularity.

Now ship it:

```bash
git add src/components/ui/ScrollSpy/ScrollSpy.tsx \
        src/components/ui/ScrollSpy/ScrollSpy.module.scss
git commit -m "fix(ScrollSpy): anchor highlight label via \`right\` instead of translate(-100%)

The portaled active label was landing to the right of the rail and
clipping past the viewport. Root cause: \`translate(-100% - 8px)\` on
.highlightLabelAnchor resolves -100% against the element's own rendered
width. On first paint the fixed element has not been laid out yet, so
self-width = 0, the x-shift = -8px only, and the label sits at r.left
(the notch's left edge) — on the far right of the viewport.

Fix: switch from left+translate(-100%) to CSS \`right\` positioning.
\`right = window.innerWidth - notch.left + GAP\` places the label's right
edge exactly at the notch's left gutter — identical geometry to the
in-rail .label rule (right: calc(100% + 1x)). Transform reduces to
translateY(-50%) for vertical centering only; no self-width dependency.

Refs: AP-070 (framer-motion / CSS transform clobber family),
      FB-156 (this exact bug report)"
```

